/**
 * Merge a new run into existing history.
 * Handles trimming old runs and cleaning up their screenshots.
 */

import { readFileSync, writeFileSync, existsSync, mkdirSync, rmSync } from 'node:fs';
import { dirname, join } from 'node:path';

export function mergeHistory(opts) {
  const {
    historyPath,
    newRunPath,
    outputPath,
    maxRuns = 50,
    screenshotsBase = null,
  } = opts;

  // Read existing history (or start empty)
  let history = [];
  if (existsSync(historyPath)) {
    try {
      history = JSON.parse(readFileSync(historyPath, 'utf8'));
    } catch {
      history = [];
    }
  }

  // Read new run
  const newRun = JSON.parse(readFileSync(newRunPath, 'utf8'));

  // Prepend new run
  history.unshift(newRun);

  // Trim and collect removed runs
  const removed = history.splice(maxRuns);

  // Clean up screenshots for removed runs
  if (screenshotsBase && removed.length > 0) {
    for (const run of removed) {
      const runDir = join(screenshotsBase, `run-${run.id}`);
      if (existsSync(runDir)) {
        rmSync(runDir, { recursive: true, force: true });
      }
    }
  }

  // Write output
  const outDir = dirname(outputPath);
  mkdirSync(outDir, { recursive: true });
  writeFileSync(outputPath, JSON.stringify(history, null, 2));
}
